#include <iostream>
#include <vector>
#include <print>

void reportScores(const std::vector<int>& scores)
{
    int sum = 0;
    int passCount = 0;

    for (std::ptrdiff_t i = 0; i < std::ssize(scores); ++i)
    {
        int score = scores[i];
        // Explicit parentheses prevent operator-precedence surprises
        bool outOfRange = ((score < 60) | (score > 100)) != 0;

        if (!outOfRange)
        {
            std::println("Score {}: PASS", score);
            ++passCount;
        }
        else
        {
            std::println("Score {}: FAIL", score);
        }

        sum += score;
    }

    std::println("Total: {}", sum);
    std::println("Pass count: {}", passCount);
}

int main()
{
    int n{};
    std::cin >> n;

    std::vector<int> scores(n);
    for (int i = 0; i < n; ++i)
        std::cin >> scores[i];

    reportScores(scores);
}

