#include <cassert>
#include <expected>
#include <iostream>
#include <stdexcept>
#include <string>
#include <format>

auto safe_divide(int dividend, int divisor) -> std::expected<int, std::string>
{
    if (divisor == 0)
        return std::unexpected(std::string{"division by zero"});
    if (divisor < 0)
        throw std::runtime_error(std::format("negative divisor {}", divisor));
    return dividend / divisor;
}

void process_divisions(int dividend, int divisor)
{
    try
    {
        auto result = safe_divide(dividend, divisor);
        if (result)
            std::cout << "Result: " << *result << "\n";
        else
            std::cout << "Error: " << result.error() << "\n";
    }
    catch (const std::runtime_error& e)
    {
        std::cout << "Exception: " << e.what() << "\n";
    }
}

int main()
{
    int n{};
    std::cin >> n;
    for (int i = 0; i < n; ++i)
    {
        int a{}, b{};
        std::cin >> a >> b;
        process_divisions(a, b);
    }
    return 0;
}

