#include <iostream>
#include <limits>

int getIntInRange(int lo, int hi)
{
    int value{};
    while (true)
    {
        std::cout << "Enter an integer between " << lo << " and " << hi << ": ";
        std::cin >> value;

        if (std::cin.fail())
        {
            std::cin.clear();
            std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');
            std::cout << "Invalid input. Please try again.\n";
        }
        else if (value < lo || value > hi)
        {
            std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');
            std::cout << "Out of range. Please try again.\n";
        }
        else
        {
            std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n');
            return value;
        }
    }
}

int main()
{
    int result{ getIntInRange(1, 10) };
    std::cout << "You entered: " << result << '\n';
    return 0;
}

