#include <cassert>
#include <iostream>

template <typename T, int N>
struct FixedBuffer
{
    static_assert(N > 0, "Buffer capacity must be positive");
    static_assert(sizeof(T) <= 8, "Element type too large");
    T data[N]{};
};

void set_element(FixedBuffer<int, 5>& buf, int index, int value)
{
    assert(index >= 0 && index < 5);
    buf.data[index] = value;
}

int main()
{
    FixedBuffer<int, 5> buf{};

    int q{};
    std::cin >> q;

    for (int i = 0; i < q; ++i)
    {
        int index{};
        int value{};
        std::cin >> index >> value;

        if (index >= 0 && index < 5)
        {
            set_element(buf, index, value);
            std::cout << "Set index " << index << " to " << value << '\n';
        }
        else
        {
            std::cout << "Error: index " << index << " out of range\n";
        }
    }

    std::cout << "Buffer:";
    for (int i = 0; i < 5; ++i)
        std::cout << ' ' << buf.data[i];
    std::cout << '\n';

    return 0;
}
